INSERT INTO cbt_soal VALUES("1403","SOS_IPS","SOS_IPS","","44","","Akibat curah hujan yang tinggi hasil pertanian terutama tanaman cabe, bawang merah dan tanaman lainnya mengalami penurunan, sehingga mempengaruhi harga di pasaran.\nDari ilustrasi tersebut, jika dilakukan penelitian rumusan masalah yang tepat adalah â¦.\n","","","","seberapa besar curah hujan berpengaruh terhadap tanaman?"," benarkah kehidupan petani menurun?","bagaimana upaya petani dalam menghadapi cuaca buruk?","mengapa cuaca buruk?","bagaimana dampak curah hujan yang tinggi terhadap hasil pertanian yang mempengaruhi harga di pasaran?","","","","","","5","0","0","10","5");
