INSERT INTO cbt_soal VALUES("1392","SOS_IPS","SOS_IPS","","33","","Generasi muda Indonesia saat ini cenderung melupakan kesenian dan budaya bangsa. Mereka cenderung lebih senang mengonsumsi lagu dan flim asing. Jika hal ini terus dibiarkan akan mengakibatkan â¦.","","","","meningkatnya dominasi budaya daerah terhadap budaya asing","rendahnya kesadaran generasi muda terhadap budaya asing","bertambahnya pengetahuan budaya asing"," lunturnya eksistensi jati diri bangsa","meluasnya gaya hidup konsumtif","","","","","","4","0","0","10","5");
INSERT INTO cbt_soal VALUES("1391","SOS_IPS","SOS_IPS","","32","","Perubahan social dapat juga menyebabkan terjadinya dinamika kependudukan. Rendahnya tingkat mortalitas dibanding fertilitas akibat kemajuan di bidang kesehatan dapat mengakibatkan jumlah penduduk â¦.","","","","stabil","stagnan","seimbang","tetap","bertambah","","","","","","5","0","0","10","5");
