INSERT INTO cbt_soal VALUES("1389","SOS_IPS","SOS_IPS","","30","","Dalam masyarakat desa Taman Sari terjadi beragam perubahan, seperti kebiasaan, hobi dan trend. Oleh karena masyarakat tersebut selalu mengikuti perubahan maka terjadi perkembangan dan kemajuan tanpa masyarakat sadari secara bertahap. Bentuk perubahan sosial yang dimaksud dalam ilustrasi diatas adalah â¦.","","","","perubahan yang dikehendaki","perubahan yang direncanakan","perubahan regress","perubahan besar ","perubahan evolusi","","","","","","5","0","0","10","5");
INSERT INTO cbt_soal VALUES("1388","SOS_IPS","SOS_IPS","","29","","Munculnya serikat pekerja yang menyebabkan reorganisasi hubungan antara buruh dan majikan membuktikan bahwa perubahan social berpengaruh terhadap â¦.","","","","laporan social","status dan peran","ekonomi dan keuangan","struktur dan fungsi masyarakat","hasil masyarakat","","","","","","4","0","0","10","5");
INSERT INTO cbt_soal VALUES("1387","SOS_IPS","SOS_IPS","","28","","Meskipun berdekatan pulau Bali dan Madura memiliki perbedaan kebudayaan. Adat istiadat dan kebudayaan masyarakat Bali dipengaruhi oleh agama Hindu. Sementara itu adat istiadat masyarakat Madura dipengaruhi oleh agama Islam. Faktor terbentuknya masyarakat multicultural tersebut dipengaruhi oleh â¦.","","","","perbedaan sikap dalam menyerap unsur kebudayaan","system religi yang dianut masyarakatnya","sejarah masuknya agama pada masa colonial","bentuk wilayah kepulauan","letak geografis yang berjauhan","","","","","","2","0","0","10","5");
INSERT INTO cbt_soal VALUES("1386","SOS_IPS","SOS_IPS","","27","","Sikap yang harus diterapkan dalam masyarakat multicultural adalah â¦.","","","","simpati dan toleransi diantara kelompok yang berbeda","memiliki pergaulan ekslusif ","bersikap arogan terhadap kelompok lain ","fanatisme berlebihan","bergaul dengan yang sederajat","","","","","","1","0","0","10","5");
INSERT INTO cbt_soal VALUES("1385","SOS_IPS","SOS_IPS","","26","","Meskipun hidup jauh dari daerah asal, beberapa kelompok di kota besar masih menjunjung tinggi adat istiadatnya. Konsekuensi masyarakat multicultural  tersebut adalah bentuk dari â¦.","","","","integrasi","primodialisme","interseksi","konsolidasi","stereotip","","","","","","2","0","0","10","5");
INSERT INTO cbt_soal VALUES("1384","SOS_IPS","SOS_IPS","","25","","Perhatikan pernyataan berikut : <br />1) menetapnya pedagang Gujarat pada masa Hindu-Budha <br />2) rendahnya tingkat urbanisasi <br />3) keterbukaan terhadap budaya lain <br />4) banyaknya masyarakat yang tinggal di pesisir <br />5) penduduk yang tersebar di kepulauan Indonesia <br /><br />Latar belakang terbentuknya masyarakat majemuk di Indonesia adalah &hellip;.","","","","1), 2) dan 3)","1), 2) dan 4)","1), 3) dan 5)","2), 3) dan 3)","2), 3) dan 5)","","","","","","3","0","0","10","5");
INSERT INTO cbt_soal VALUES("1383","SOS_IPS","SOS_IPS","","24","","Warga masyarakat perkotaan cenderung lebih terbuka. Mereka sudah biasa berinteraksi dan bekerja sama dengan orang lain yang berbeda suku, ras dan agama. Dampak positif proses mutual akulturasi tersebut adalah â¦.","","","","menghilangkan semua perbedaan","mengurangi sentiment kelompok","memudarkan identitas kepribadian","mendorong kesamaan masyarakat","mempercepat proses integrasi social","","","","","","5","0","0","10","5");
INSERT INTO cbt_soal VALUES("1382","SOS_IPS","SOS_IPS","","23","","Selain penganut Islam, di Aceh juga terdapat masyarakat penganut agama Kristen, Hindu,  Budha dan Konghucu. Meskipun demikian kehidupan religious masyarakat Aceh tampak dalam aktivitas sehari-hari. Situasi tersebut membentuk konfigurasi social yang berupa â¦.","","","","dictator mayoritas","mayoritas dominan","tirani minoritas","minoritas seimbang","minoritas dominan","","","","","","2","0","0","10","5");
INSERT INTO cbt_soal VALUES("1381","SOS_IPS","SOS_IPS","","22","","Contoh mobilitas sebagai berikut : <br />1) usaha gigih Rizky menghasilkan beragam bisnis <br />2) Rizka tidak melanjutkan sekolah karena dirinya perempuan <br />3) kondisi politik tidak menentu menyebabkan imigran Suriah mencari suaka <br />4) suku Aborigin menjadi warga negara kelas dua di Australia <br />5) kemajuan Jakarta mengundang terjadinya urbanisasi Faktor pendorong mobilitas social berdasarkan contoh diatas adalah &hellip;.","","","","1), 2) dan 3)","1), 2) dan 4)","1), 3) dan 5)","2), 3) dan 5)","3), 4) dan 5)","","","","","","3","0","0","10","5");
INSERT INTO cbt_soal VALUES("1380","SOS_IPS","SOS_IPS","","21","","Konflik penghuni asrama dengan pemilik asrama karena kesalahpahaman akhirnya dapat diselesaikan setelah keduanya bertemu di pengadilan. Bentuk akomodasi untuk menyelesaikan konflik tersebut adalah â¦","","","","ajudikasi","mediasi","koersi","arbitrasi"," kompromi","","","","","","1","0","0","10","5");
INSERT INTO cbt_soal VALUES("1379","SOS_IPS","SOS_IPS","","20","","Skema struktur social majemuk : <br /><br /><img src=\"/unbk/pictures//Sos_2.jpg\" width=\"295\" height=\"165\" /><br /><br />Keterangan : A = Suku Jawa B = Suku Minang X = Pedagang Komunitas majemuk pada gambar tersebut mempunyai potensi integrasi dengan parameter &hellip;.","","","","suku dan daerah","agama dan suku","agama dan pekerjaan","suku dan ras","pekerjaan dan suku","","","","","","5","0","0","10","5");
INSERT INTO cbt_soal VALUES("1378","SOS_IPS","SOS_IPS","","19","","Masyarakat pedalaman di Indonesia seperti suku Asmat, suku Dayak dan lain-lainnya masih bersifat tertutup terhadap masyarakat di luar kelompoknya. Mereka berbeda dengan suku lain sehingga membentuk struktur majemuk. Faktor penyebab terjadinya kondisi tersebut adalah  â¦.","","","","masing-masing memiliki sumber kehidupan sendiri","perbedaan adat karena isolasi geografis","kekuasaan yang bersumber pada kewibawaan","pemimpin yang tanggap terhadap budaya asing","kepulauan yang strategis","","","","","","2","0","0","10","5");
INSERT INTO cbt_soal VALUES("1377","SOS_IPS","SOS_IPS","","18","","Seseorang yang memiliki tingkat pendidikan tinggi biasanya akan mendapatkan penghormatan dari masyarakat. Oleh karena itu, banyak anggota masyarakat berusaha agar anaknya sekolah sampai jenjang perguruan tinggi. Hal ini menunjukkan adanya ikatan social antara â¦.","","","","status social dan wewenang","pengetahuan dan wewenang","pendidikan dan wewenang","pendidikan dan kehormatan","pengetahuan dan kekuasaan","","","","","","4","0","0","10","5");
INSERT INTO cbt_soal VALUES("1376","SOS_IPS","SOS_IPS","","17","","Banyak warga desa Sukamaju enggan membuat e-KTP karena ada pungutan liar. Warga yang memberi imbalan kepada petugas mendapat pelayanan terlebih dahulu. Kondisi ini mendorong warga melancarkan protes terhadap pemerintah daerah. Dari ilustrasi tersebut dapat diketahui latar belakang terjadinya konflik social adalah â¦.","","","","perbedaan kebudayaan","perbedaan keyakinan ","perbedaan ketimpangan","perbedaan kepentingan","perbedaan keinginan","","","","","","4","0","0","10","5");
INSERT INTO cbt_soal VALUES("1375","SOS_IPS","SOS_IPS","","16","","Gambar pelapisan social : <br /><br /><img src=\"/unbk/pictures//Sos_1.jpg\" width=\"181\" height=\"162\" /><br /><br />Keterangan : 1 = pengusaha 2 = pimpinan perusahaan 3 = karyawan perusahaan Pelapisan social pada gambar tersebut bersifat terbuka karena &hellip;.","","","","jumlah pengusaha kuat modal banyak","pendidikan pengusaha cukup tinggi","dapat meningkatkan karir di perusahaan","pengalaman kerja diperlukan di perusahaan","adanya struktur kekuasaan dalam perusahaan","","","","","","3","0","0","10","5");
INSERT INTO cbt_soal VALUES("1374","SOS_IPS","SOS_IPS","","15","","Seorang anak penambal ban akhirnya dapat mewujudkan impiannya menjadi dokter karena usaha kerasnya dalam belajar dan mencari beasiswa. Setelah menjadi dokter, ia memiliki status sosial lebih tinggi dalam masyarakat. Status sosial yang diperoleh dokter tersebut merupakan contoh &hellip;.","","","","peran sosial","<em>ascribed status</em>","<em>assigned status</em>","<em>achieved status</em>","stratifikasi sosial","","","","","","4","0","0","10","5");
INSERT INTO cbt_soal VALUES("1195","BIND_ALL","BINDO","","51","","Bacalah teks tersebut dengan saksama! <br /><br />(1) Di dunia bisnis sering terdengar adanya dua pandangan yang kontras. <br />(2) Satu pihak mengatakan, pada masa krisis tundalah investasi, hati-hatilah dalam pengeluaran. <br />(3) Sementara pihak lain berpandangan, pada masa krisis berinvestasilah, tetapi harus dengan cara cerdas. <br />(4) Dari kedua pandangan ini, pandangan kedualah yang ditempuh oleh maskapai penerbangan nasional Garuda lndonesia. <br />(5) Dalam kondisi krisis seperti sekarang ini, Garuda menunda pembukaan rute-rute baru dan pembelian pesawat - pesawat mutakhir. <br /><br />Gagasan tidak logis terdapat pada kalimat","","","","Kelima","Ketiga","Kedua","Keempat","Pertama","","","","","","1","0","0","10","5");
INSERT INTO cbt_soal VALUES("1192","BIND_ALL","BINDO","","48","","Cermati ilustrasi berikut! <br /><br />Keprihatinan saat ini muncul sebab tamatan Sekolah Menengah Atas dilecehkan masyarakat, sedangkan <em>korporate</em> tidak dapat memanfaatkan mereka lantaran mereka dianggap tidak dapat memenuhi <em>kualivikasi</em> yang ditentukan. Oleh karena itu, setiap <em>aktifitas</em> di sekolah harus mampu mengasah keterampilan siswa agar lulusannya sesuai dengan permintaan pasar. <br /><br />Kata serapan yang tepat untuk memperbaiki kata yang bercetak miring adalah...","","","","Korporate, kualifikasi, aktivitas","Korporat, kualivikasi, aktivitas","Korporasi, kualifikasi, aktifitas","Korporat, kualifikasi, aktivitas","Korporasi, kualifikasi, aktivitas","","","","","","5","0","0","10","5");
INSERT INTO cbt_soal VALUES("1193","BIND_ALL","BINDO","","49","","Bacalah teks berikut ini! <br /><br />Sejak perpisah dengan burung kesayangannya, Mbah Parto, bukan sakit encok seperti biasanya, namun sakitnya lebih merupakan sakit rohani ketimbang sakit jasmani. Tiga bulan yang lalu, burung perkutut yang sudah \"kung&rdquo; itu dibeli Pak Umar. Sebetulnya, Mbah Parto tak hendak melepaskan burung kesayangannya. Namun, karena Pak Umar mendesak dan meninggaikan penawaran sampai delapan ratus rupiah, akhimya mbah Parto merelakan perkutut itu dibeli. la mengira dengan uang sebanyak itu, dia dapat membeli perkutut lagi dan sisanya untuk membeli kebutuhan hidup. Namun, yang terjadi di luar perkiraannya. Semenjak berpisah dengan burung perkututnya, Mbah Parto justru menderita. Tubuhnya semakin kurus dan pada akhimya, jasmaninya pun tak kuat.Ia terbaring sakit. <br /><br />Amanat yang terkandung dalam penggalan cerpen di atas adalah ....","","","","jangan memaksakan kehendak","jangan menyayangi sesuatu dengan berlebihan","jangan tergiur dengan uang banyak","jangan tergesa-gesa membuat keputusan","jangan menyayangi binatang","","","","","","2","0","0","10","5");
INSERT INTO cbt_soal VALUES("1194","BIND_ALL","BINDO","","50","","Bacalah kutipan cerpen berikut! <br /><br /><strong>Teks 1</strong> <br />Ada banyak Banun di perkampungan lereng bukit yang sejak dulu tanahnya subur hingga tersohor sebagai daerah penghasil padi kwalitet nomor satu itu. Pertama, Banun dukun patah-tulang yang dangau usangnya kerap didatangi laki-laki pekerja keras bila pinggang atau pangkal lengannya terkilir akibat terlampau bergairah mengayun cangkul. Disebut-sebut, kemampuan turun-temurun Banun ini tak hanya ampuh mengobati patah tulang. <br /><br />Banun, Damhuru Muhammad <br /><br /><strong>Teks 2</strong> <br />Begitulah pentingnya Makaji. Tanpa campur tangannya, kenduri terasa hambar, sehambar gulai kambing dan gulai rebung karena bumbu-bumbu tak diracik oleh tangan dingin lelaki itu. Makaji tidak pernah keberatan membantu keluarga mana saja yang hendak menggelar pesta. Makaji tak pilih kasih, meski ia satu-satunya juru masak yang masih tersisa di Lareh Panjang. <br /><br />Juru Masak, Damhuri Muhammad <br /><br /><br />Persamaan unsur intrinsik kedua tersebut adalah ...","","","","Menceritakan seseorang yang menjadi bahan pembicaraan di lingkungannya.","Banyak tokoh sebagai orang seperti Banun dan juru masak.","Pekerjaan kedua tokoh cerita sangat berat.","Hasil pekerjaan tokoh cerita sangat mengagumkan.","Latar kedua cerita berada di keluarga berada.","","","","","","5","0","0","10","5");
INSERT INTO cbt_soal VALUES("1187","BIND_ALL","BINDO","","43","","Cermati hikayat berikut! <br /><br />Syahdan maka Masyhudulhakk pun tertawa, seraya berkata, &ldquo;Jika sungguh istrimu perempuan ini, siapa nama mentuamu laki-laki dan mentuamu perempuan, dan di mana kampung tempat ia duduk?\" <br />Maka tiadalah terjawab oleh laki-laki itu. Maka disuruh oleh Masyhudulhakk jauhkan laki-laki Bedawi itu. Setelah itu maka dipanggilnya pula orang tua itu. Maka kata Masyhudulhakk, \"Hai orang tua, sungguhlah perempuan itu istrimu sebenar-benamya?\" <br />Maka kata orang tua itu, \"Daripada mula awalnya.\" Kemudian maka dikatakannya, siapa mentuanya laki-laki dan perempuan dan di mana tempat duduknya <br />Maka Masyhudulhakk dengan sekalian orang banyak itu pun tahulah akan salah Bedawi itu dan kebenaran orang tua itu. Maka hendaklah disakiti oleh Masyhudulhakk akan Bedawi itu. Maka Bedawi itu pun mengakulah salahnya. Demikian juga perempuan celaka itu. Lalu didera oleh Masyhudulhakk akan Bedawi itu serta dengan perempuan celaka itu seratus kali. Kemudian maka disuruhnya tobat Bedawi itu, jangan lagi ia berbuat pekerjaan demikian itu. <br /><br />Inti cerita melayu klasik tersebut adalah...","","","","Keegoisan seorang Masyhudulhakk","Bedawi mengakui kesalahannya","Balasan atas perbuatan Bedawi","Keraguan Masyhudulhakk terhadap perempuan yang dianggap istri oleh Bedawi","Masyhudulhakk yakin bahwa perempuan itu istri Bedawi","","","","","","3","0","0","10","5");
INSERT INTO cbt_soal VALUES("1188","BIND_ALL","BINDO","","44","","Cermati hikayat berikut! <br /><br />Syahdan maka Masyhudulhakk pun tertawa, seraya berkata, &ldquo;Jika sungguh istrimu perempuan ini, siapa nama mentuamu laki-laki dan mentuamu perempuan, dan di mana kampung tempat ia duduk?\" <br />Maka tiadalah terjawab oleh laki-laki itu. Maka disuruh oleh Masyhudulhakk jauhkan laki-laki Bedawi itu. Setelah itu maka dipanggilnya pula orang tua itu. Maka kata Masyhudulhakk, \"Hai orang tua, sungguhlah perempuan itu istrimu sebenar-benamya?\" <br />Maka kata orang tua itu, \"Daripada mula awalnya.\" Kemudian maka dikatakannya, siapa mentuanya laki-laki dan perempuan dan di mana tempat duduknya <br />Maka Masyhudulhakk dengan sekalian orang banyak itu pun tahulah akan salah Bedawi itu dan kebenaran orang tua itu. Maka hendaklah disakiti oleh Masyhudulhakk akan Bedawi itu. Maka Bedawi itu pun mengakulah salahnya. Demikian juga perempuan celaka itu. Lalu didera oleh Masyhudulhakk akan Bedawi itu serta dengan perempuan celaka itu seratus kali. Kemudian maka disuruhnya tobat Bedawi itu, jangan lagi ia berbuat pekerjaan demikian itu. <br /><br />Nilai moral yang terdapat dalam kutipan sastra melayu klasik adalah...","","","","Hendaklah tidak membiarkan perempuan sendirian","Berilah sanksi sesuai kadar kesalahan","Jauhilah sifat keragu-raguan","Tegurlah siapapun yang berbuat salah","Kejujuran adalah modal utama dalam pergaulan","","","","","","5","0","0","10","5");
INSERT INTO cbt_soal VALUES("1189","BIND_ALL","BINDO","","45","","Cermati kutipan resensi berikut! <br /><br />Pengarang amat cermat memberikan gambaran tentang watak. Watak cerita si Teto (anak kolong yang dilahirkan di Garnisun Magelang) yang beringas dilukiskan dengan kenakalan, keberanian, kenekatan, sinis, dan sarkastis, tetapi juga romantis. Si teto, yang kaya perasaan dan emosi, kecewa dan geram terhadap Belanda yang harus kalah dan terpaksa kagum kepada pemimpin-pemimpin republik yang dianggapnya kampungan. <br /><br />Kalimat resensi yang menyatakan keunggulan dalam kutipan resensi tersebut adalah...","","","","Kesederhanaan tokoh sangat menonjol dalam cerita ini","Pengarang mampu meramu alur dengan baik","Tokoh dalam cerita digambarkan sangat hidup","Pengarang sangat teliti dalam menggambarkan watak tokoh dalam cerita","Pengarang menampilkan tokoh dengan kepribadian yang unik","","","","","","4","0","0","10","5");
INSERT INTO cbt_soal VALUES("1191","BIND_ALL","BINDO","","47","","Cermati kutipan gurindam berikut! <br /><br />Apabila terpelihara mata, <br />sedikitlah cita-cita. <br /><br />Maksud isi gurindam tersebut adalah&hellip;","","","","Peliharalah mata agar tidak terkena penyakit","Jagalah penglihatanmu agar keinginan-keinginanmu selalu mengarah ke hal yang positif","Cita-cita seseorang dapat diketahui dari mata orang tersebut","Gantungkanlah cita-citamu setinggi langit","Semua cita-cita baik asal kita yakin","","","","","","2","0","0","10","5");
INSERT INTO cbt_soal VALUES("1190","BIND_ALL","BINDO","","46","","Cermati kutipan paragraf berikut! <br /><br />Setiap tanggal 17 Agustus, rakyat Indonesia selalu memperingati hari ulang tahun kemerdekaannya dengan <em>agak meriah.</em> Begitu juga dengan tahun ini, terasa <em>ramai amat</em> daripada tahun lalu. Berbagai kegiatan yang bersifat menghibur selalu mengundang perhatian masyarakat. Hal ini terlihat dari para remajanya yang menjadi panitia beberapa kegiatan. Sementara itu, anak-anak <em>malas sekali</em> mengikuti berbagai perlombaan. <br /><br />Frasa adjektiva yang tepat untuk memperbaiki frasa yang bercetak miring dalam kutipan tersebut adalah...","","","","Sangat meriah, amat meriah, sangat antusias","Sangat meriah, amat ramai, sangat malas","Amat meriah, amat besar,sangat antusias","Sangat ramai, amat meriah, sangat antusias","Sangat ramai, sangat meriah, agak malas","","","","","","2","0","0","10","5");
INSERT INTO cbt_soal VALUES("1182","BIND_ALL","BINDO","","38","","Bacalah puisi berikut ini ! <br /><br /><strong>Cintaku Jauh di Pulau</strong> <br /><br />Cintaku jauh di pulau <br />Gadis manis sekarang iseng sendiri <br />Perahu melancar, bulan nemancar <br />di leher kukalungkan oleh-oleh buat si pacar <br />ingin membantu, laut terang, tapi terasa <br />aku tak kan sampai padanya <br />Di air yang tenang, di angin mendayu di perasaan penghabisan segala mengaju Ajal bertahta, sambil berkata, &ldquo;Tujukan perahu ke pangkuanku saja&rdquo; <br />Chairil Anwar <br />lnti puisi di atas tentang . . . .","","","","Perpisahan cinta karena iseng.","Kegagalan cinta karena kebimbangan.","Kegagalan cinta karena direnggut ajal.","Perpisahan cinta karena kekasi mengembara.","Kegagalan cinta karena tinggal berjauhan.","","","","","","3","0","0","10","5");
INSERT INTO cbt_soal VALUES("1183","BIND_ALL","BINDO","","39","","Bacalah teks berikut ini! <br /><br />Di dalam buku ini dikumpulkan beberapa karangan ldrus semenjak kedatangan Jepang tahun 1942 dan sesudah 17 Agustus 1945. Dalam,\"Ave Maria\" dan lain-lain karangannya yang mula-mula kelihatan romantis yang merawankan hati, di dalam sandiwara \"Kejahatan Membalas Dendam&rdquo; pendalaman ke dasar jiwa. Dengan ini, ldrus mungkin tidak menyadari telah memulai percobaan baru dalam dunia penulisan sandiwara. <br /><br />Resensi H.B. Jassin atas buku ldrus<em> Dari Ave Maria ke Jalan Lain ke Roma</em> tersebut pada bagian ....","","","","identitas buku","latar belakang buku","ikhtisar buku","keunggulan buku","nilai buku","","","","","","5","0","0","10","5");
INSERT INTO cbt_soal VALUES("1184","BIND_ALL","BINDO","","40","","Cermati puisi berikut! <br /><br />TIRANI <br />Tirani adalah kata <br />Yang melahirkan banyak pengertian <br />Yang tak berkata <br />Tirani adalah pikiran <br />Yang dipindahkan kedalam slogan <br />Yang merantau pikiran <br />Tirani adalah kebebasan <br />Di tengah padang tandus tak bertepi <br />Yang melimpahkan kebebasan <br />Tirani adalah kekuasaan <br />Yang ....... di atas segala penggelapan <br />Yang menimbulkan kekuasaan <br /><br />(Bur Rasuanto) <br /><br />Makna lambang <em>padang tandus tak bertepi</em> pada larik puisi tersebut adalah..","","","","Keinginan yang meluap-luap","Aspirasi besar yang tidak menemukan media penyaluran","Padang yang tidak ada pepohonan","Padang yang tidak pernah turun hujan","Aspirasi yang tidak terkendali","","","","","","5","0","0","10","5");
INSERT INTO cbt_soal VALUES("1185","BIND_ALL","BINDO","","41","","<table class=\"table\">INSERT INTO cbt_soal VALUES("1186","BIND_ALL","BINDO","","42","","Cermati hikayat berikut! <br /><br />Syahdan maka Masyhudulhakk pun tertawa, seraya berkata, &ldquo;Jika sungguh istrimu perempuan ini, siapa nama mentuamu laki-laki dan mentuamu perempuan, dan di mana kampung tempat ia duduk?\" <br />Maka tiadalah terjawab oleh laki-laki itu. Maka disuruh oleh Masyhudulhakk jauhkan laki-laki Bedawi itu. Setelah itu maka dipanggilnya pula orang tua itu. Maka kata Masyhudulhakk, \"Hai orang tua, sungguhlah perempuan itu istrimu sebenar-benamya?\" <br />Maka kata orang tua itu, \"Daripada mula awalnya.\" Kemudian maka dikatakannya, siapa mentuanya laki-laki dan perempuan dan di mana tempat duduknya <br />Maka Masyhudulhakk dengan sekalian orang banyak itu pun tahulah akan salah Bedawi itu dan kebenaran orang tua itu. Maka hendaklah disakiti oleh Masyhudulhakk akan Bedawi itu. Maka Bedawi itu pun mengakulah salahnya. Demikian juga perempuan celaka itu. Lalu didera oleh Masyhudulhakk akan Bedawi itu serta dengan perempuan celaka itu seratus kali. Kemudian maka disuruhnya tobat Bedawi itu, jangan lagi ia berbuat pekerjaan demikian itu. <br /><br />Karakteristik sastra melayu klasik yang terdapat dalam kutipan tersebut adalah...","","","","Kesaktian tokoh","Statis","Menggunakan bahasa yang tidak sesuai kaidah","Istana sentris","Menggunakan alur maju","","","","","","4","0","0","10","5");
INSERT INTO cbt_soal VALUES("1180","BIND_ALL","BINDO","","36","","Cermati ilustrasi berikut! <br /><br />Memberikan bantuan pangan kepada pihak lain Aku harus biasa pada dingin malam. Terkadang harus menunggui sampai penuh mengenang. Tak jarang sampai jauh malam menunggu orang lain pulang. Dan jika sudah sepi kututuplah lubang air ke sawah lain. Air mengalir ke sawahku semua. <br /><br />Ungkapan yang tepat untuk menggambarkan watak tokoh Aku adalah...","","","","Tangan kanan","Cuci tangan","Ringan tangan","Angkat tangan","Sembunyi tangan","","","","","","5","0","0","10","5");
INSERT INTO cbt_soal VALUES("1181","BIND_ALL","BINDO","","37","","Cermatilah paragraf berikut! <br /><br />Green House, sebuah tempat tinggal di kawasan hijau Jakarta. Kawasan ini memiliki daya tarik khusus supaya penggemar seni. Mereka yang menyukai kehidupan alami atau seni, inilah tempatnya. Banyak seniman yang tampak di rumah mereka menggelar kemampuan seni seperti melukis, latihan drama di kebun, bahwa menari di panggung rumah. Justru inilah daya tarik yang muncul. Setiap orang ingin melihat keunikan ini. <br /><br />Kata penghubung yang tepat untuk memperbaiki kata penghubung yang bercetak miring pada paragraf tersebut adalah...","","","","Agar,dan,bahkan","Agar, dan bahkan","Demi, serta, bahkan","Untuk, serta, bahkan","Bagi,dan, bahkan","","","","","","5","0","0","10","5");
INSERT INTO cbt_soal VALUES("1177","BIND_ALL","BINDO","","33","","Cermati paragraf berikut! <br /><br />Dewasa ini semakin banyak remaja terjerumus ke dalam perilaku seks bebas. Hal ini terjadi karena rendahnya pemahaman remaja terhadap seksualitas. Sementara itu, orang tua yang seharusnya mendampingi mereka seringkali tidak mempunyai waktu karena kesempatan mereka tersita habis untuk mencari nafkah guna mencukupi kebutuhan hidup yang semakin tinggi. Di samping meyebabkan remaja terjerumus ke perilaku seks bebas, sempitnya waktu orang tua dalam menghadapi remaja juga menyebabkan remaja jatuh ke tindak kenakalan remaja, bahkan sampai pada penyalahgunaan narkotika. <br /><br />Opini penulis dalam tajuk tersebut adalah...","","","","Makin banyak remaja terjerumus ke dalam perilaku seks bebas","Orang tua lebih banyak waktu untuk memenuhi kebutuhan hidup","Kesibukan orang tua juga menyebabkan kenakalan remaja","Orang tua seharusnya selalu mendampingi dan mempunyai waktu lebih untuk putra putri mereka","Salah satu contoh kenakalan remaja adalah penyalahgunaan narkotika","","","","","","3","0","0","10","5");
INSERT INTO cbt_soal VALUES("1178","BIND_ALL","BINDO","","34","","Cermati paragraf berikut! <br /><br />Dewasa ini semakin banyak remaja terjerumus ke dalam perilaku seks bebas. Hal ini terjadi karena rendahnya pemahaman remaja terhadap seksualitas. Sementara itu, orang tua yang seharusnya mendampingi mereka seringkali tidak mempunyai waktu karena kesempatan mereka tersita habis untuk mencari nafkah guna mencukupi kebutuhan hidup yang semakin tinggi. Di samping meyebabkan remaja terjerumus ke perilaku seks bebas, sempitnya waktu orang tua dalam menghadapi remaja juga menyebabkan remaja jatuh ke tindak kenakalan remaja, bahkan sampai pada penyalahgunaan narkotika. <br /><br />Permasalahan opini dalam kutipan tersebut ditujukan kepada....","","","","Pihak keamanan","Orang tua","Remaja","Guru","Pelajar","","","","","","3","0","0","10","5");
INSERT INTO cbt_soal VALUES("1179","BIND_ALL","BINDO","","35","","Bacalah  teks tersebut dengan saksama!\n\n(1) Di dunia bisnis sering terdengar adanya dua pandangan yang kontras.\n(2) Satu pihak mengatakan, pada masa krisis tundalah investasi, hati-hatilah\ndalam pengeluaran. (3) Sementara pihak lain berpandangan, pada masa krisis\nberinvestasilah, tetapi harus dengan cara cerdas. (4) Dari kedua pandangan ini,\npandangan kedualah yang ditempuh oleh maskapai penerbangan nasional Garuda\nlndonesia. (5) Dalam kondisi krisis seperti sekarang ini, Garuda menunda pembukaan rute-rute baru dan pembelian pesawat - pesawat mutakhir.\n\n\nGagasan tidak logis terdapat pada kalimat","","","","Pertama ","Kedua  ","Ketiga","Keempat","Kelima","","","","","","5","0","0","10","5");
INSERT INTO cbt_soal VALUES("1175","BIND_ALL","BINDO","","31","","Cermati paragraf berikut! <br /><br />Hujan yang turun ....... selama tiga hari ini semakin memperparah kondisi masyarakat di daerah Langkat. Pemda setempat telah mempersiapkan segala sesuatu untuk membantu masyarakat yang terkena bencana. Tidak hanya itu, secara umum pemda sumut pun telah mengerahkan segala upaya, baik ...... makanan maupun tenaga medis untuk membantu korban bencana alam yang kali ini ...... luar biasa besarnya. <br /><br />Kata ulang yang tepat untuk melengkapi bagian rumpang pada paragraf tersebut adalah....","","","","terus-menerus, bahan-bahan, benar-benar","terus-menerus, bahan-bakar, benar-benar","terus-terusan,bahan-bahan,sungguh-sungguh","terus-terusan,bahan-bakar,benar-benar","terus-menerus, bahan-bahan, sungguh-sungguh","","","","","","1","0","0","10","5");
INSERT INTO cbt_soal VALUES("1176","BIND_ALL","BINDO","","32","","Cermati paragraf tersebut! <br /><br />INSERT INTO cbt_soal VALUES("1174","BIND_ALL","BINDO","","30","","Cermati puisi berikut <br /><br /><strong>TERJAGA DARI MIMPI</strong> <br /><em>Suara itu lebih deras </em><br /><em>dari gelombang segala gelombang </em><br /><em>dari debur darah, dari doa-doa malammu </em><br /><em>sebuah sungai mengusung bongkahan batu rindu </em><br /><em>sampai muara, lautan lidahnya melecut jantungmu </em><br /><em>adalah mimpi yang tiba-tiba terjaga </em><br /><em>jendela itu masih membuka menutup </em><br /><em>dimainkan angin, dan bulan diselaputi awan</em> <br />Abdul Wachid B.S. <br /><br />Suasana yang tergambar dalam puisi tersebut adalah...","","","","kesedihan","kegelisahan","ketakutan","kedamaian","kegembiraan","","","","","","1","0","0","10","5");
INSERT INTO cbt_soal VALUES("1171","BIND_ALL","BINDO","","27","","Cermati paragraf berikut! <br /><br />Gulma sering menjadi masalah dalam penerapan olah tanah konservasi (OTK). Penanggulangan gulma dengan pemberian mulsa terkadang kurang efektif. Dalam keadaan demikian perlu diupayakan penggunaan herbisida. Satu hal yang perlu diperhatikan dalam rangka penggunaan herbisida adalah dampaknya terhadap lingkungan, terlebih pada tempat-tempat dengan muka air tanah yang dangkal dan mata air yang airnya dipergunakan untuk memenuhi kebutuhan hidup sehari-hari. <br /><br />Kritik yang tepat terhadap isi wacana tersebut adalah &hellip;","","","","Penanggulangan gulma dengan pemberian mulsa kurang efektif","Dampak terhadap lingkungan dalam penggunaan herbisida perlu diperhatikan","Air dipergunakan untuk kebutuhan sehari-hari","Memang gulma merupakan masalah besar dalam menerapkan OTK","Penggunaan herbisida untuk penanggulangan gulma penting","","","","","","2","0","0","10","5");
INSERT INTO cbt_soal VALUES("1172","BIND_ALL","BINDO","","28","","Cermati paragraf di bawah ini! <br /><br />Bisnis penerbangan adalah bisnis yang mahal dan rumit. Persaingan pun sangat ketat. Di bisnis seperti inilah Merpati harus terjun. Sementara itu, pada saat yang sama perusahaan ini harus mengemban misi yang tidak ringan, yaitu melayani rute-rute perintis. Rute seperti ini jelas merupakan rute komersial, alias besar kemungkinan merugi, namun demi kepentingan nasional rute ini harus dijalani. <br /><br />Kalimat kesimpulan yang sesuai dengan isi paragraf tersebut adalah...","","","","Bisnis penerbangan hanya untuk orang yang berduit saja","Bisnis penerbangan mempunyai daya saing yang ketat","Demi kepentingan nasional bisnis penerbangan tetap berjalan betapapun mahal dan rumit","Bisnis ini juga melayani rute-rute perintis","Bisnis penerbangan adalah bisnis yang sangat menjanjikan","","","","","","3","0","0","10","5");
INSERT INTO cbt_soal VALUES("1173","BIND_ALL","BINDO","","29","","Cermati puisi berikut <br /><br /><strong>TERJAGA DARI MIMPI</strong> <br /><em>Suara itu lebih deras </em><br /><em>dari gelombang segala gelombang </em><br /><em>dari debur darah, dari doa-doa malammu </em><br /><em>sebuah sungai mengusung bongkahan batu rindu </em><br /><em>sampai muara, lautan lidahnya melecut jantungmu </em><br /><em>adalah mimpi yang tiba-tiba terjaga </em><br /><em>jendela itu masih membuka menutup </em><br /><em>dimainkan angin, dan bulan diselaputi awan</em> <br />Abdul Wachid B.S. <br /><br />Maksud puisi tersebut adalah &hellip;.","","","","kemuliaan Tuhan tidak dapat ditandingi","keadaan di pinggir pantai yang indah","suara debur ombak yang menggetarkan hati","suara debur ombak yang menggetarkan hati","penyesalan atas perbuatan salah yang dilakukan sebelumnya","","","","","","1","0","0","10","5");
INSERT INTO cbt_soal VALUES("1168","BIND_ALL","BINDO","","24","","Cermati ilustrasi berikut! <br /><br />Bapak Abdul Gofur seorang pengusaha yang sukses. Dia banyak memberi bantuan kepada pengusaha kecil yang memerlukan modal. Pengusaha kecil wajib mengembalikan pinjamannya sesuai dengan janji yang disepakati. <br /><br />Peribahasa yang tepat untuk ilustrasi di atas adalah&hellip;","","","","Besar pasak daripada tiang","Lempar batu sembunyi tangan","Tong kosong nyaring bunyinya","Bila mengikat hendaklah menali","Berat sama dipikul , ringan sama dijinjing","","","","","","4","0","0","10","5");
INSERT INTO cbt_soal VALUES("1169","BIND_ALL","BINDO","","25","","Cermati paragraf berikut! <br /><br />(1) Kasus HIV/AIDS dikalangan pelajar semakin meningkat. (2) Karena itulah, informasi tentang masalah daripada HIV/AIDS sangat penting sekali. (3) Namun, memasukkan materi tentang HIV/AIDS secara khusus ke dalam mata pelajaran tersendiri memang sulit. (4) Salah satu solusinya adalah dengan mensisipkan materi ini ke dalam mata pelajaran yang berdekatan, misalnya biologi, agama, olahraga dan kesehatan (5) Peran serta pihak sekolah untuk menangani masalah ini sangat diperlukan. <br />(Warta Kota, 2007) <br /><br /><br />Kalimat rancu dalam penggalan berita di atas adalah kalimat nomor&hellip;","","","","(1) dan (3)","(2) dan (4)","(3) dan (5)","(1) dan (4)","(1) dan (5)","","","","","","2","0","0","10","5");
INSERT INTO cbt_soal VALUES("1170","BIND_ALL","BINDO","","26","","Cermati paragraf berikut! <br /><br />Judi dilihat dari sudut pandang apa pun adalah judi. Bermain judi ditinjau dari sudut pandang agama juga dilarang. Di Indonesia undang-undang antiperjudian telah dibuat, yaitu UU nomor 7 tahun 1974 dan Kepres tahun 1995. Jadi, judi di Indonesia dilarang keras. <br /><br />Maksud penulis pada penggalan tajuk rencana tersebut adalah &hellip;","","","","Judi ditinjua dari segi agama , undang-undang, dan Kepres tahun 1995 tidak dibenarkan.","Judi perlu dilokalisasikan karena dibenarkan oleh pemerintah daerah","Hanya agama saja yang tidak membenarkan keberadaan judi di Indonesia","Lokalisasi judi dapat dibenarkan asalkan mendapat persetujuan DPRD.","Undang-undang perjudian di Indonesia tidak ditegakan oleh pemerintah","","","","","","1","0","0","10","5");
INSERT INTO cbt_soal VALUES("1167","BIND_ALL","BINDO","","23","","Cermati paragraf berikut! <br /><br />Ibu guru selalu <strong>bilang</strong>, semua siswa tidak boleh <em><strong>menyontek</strong></em> pekerjaan temannya. Jika ketahuan, Ibu guru akan memberikan <strong>sanksi</strong> kepada siswa tersebut. Oleh karena itu,janganlah melakukan tindakan mencontek itu. <br /><br />Perbaikan kata tidak baku yang dicetak tebal dalam paragraf tersebut adalah&hellip;","","","","Mengomentari, mencontek, sanksi","Mengatakan, menyontek, sangsi","Memberitahukan, mencontek, hukuman","Mengatakan, mencontek, sanksi","Memberitahukan, mencontek, sanksi","","","","","","3","0","0","10","5");
INSERT INTO cbt_soal VALUES("1166","BIND_ALL","BINDO","","22","","<strong>Bacalah teks berikut dengan saksama!</strong> <br /><br />(1) Bukan hanya satelit yang dapat digunakan untuk memestikan tempat berkumpulnya ikan. (2) Ada juga teknologi hidroakustik, yaitu upaya rnemperoleh informasi tentang objek di bawah laut dengan memancarkan gelombang suara. (3) Gema yang dipantulkan oleh gelombang suara yang dipancarkan ke dasar laut membawa informasi kelimpahan ikan di suatu perairan. (4) Pendeteksian ikan dengan menggunakan sistem hidroakustik disebut echo sounder atau fish finder. (5) kelebihan dari metode ini adatah tingkat keakuratannya tinggi. <br /><br />Ringkasan teks tersebut adalah ....","","","","Teknologi hidroakustik lebih akurat dalam menentukan lokasi ikan.","Jumlah ikan di suatu tempat dapat dipastikan dengan satelit dan teknologi hidro.","Satelit dan teknologi hidroakustik merupakan satu-satunya cara untuk memastikan jumlah ikan yang berkumpul.","Untuk memastikan lokasi berkumpulnya ikan sebaiknya menggunakan teknologi hidroakustik karena lebih akurat.","Selain menggunakan satelit, teknologi hidroakustik dapat digunakan untuk memastikan tempat berkumpulnya ikan.","","","","","","5","0","0","10","5");
INSERT INTO cbt_soal VALUES("1165","BIND_ALL","BINDO","","21","","Cermati cerpen berikut! <br /><br />Penyakit lupa Ira pernah dua kali dimanfaatkan pembantunya. Itu yang diketahui. Ya, si pembantu mencuri uang. Dan Bonar yang memergokinya. Ira kena semprot Bonar, yang samar-samar mulai menyadari sifat teledor istrinya. Sejak itu, Ira takut sekali kepada Bonar. Apapun yang terjadi, terutama yang menyangkut sifat pelupanya, dia tidak ingin Bonar mengetahui. <br />(<em>Utang</em>, N. Riantiarno) <br /><br />Konflik yang tergambar dalam penggalan cerpen tersebut adalah&hellip;","","","","Ira yang ketakutan kalau sifat pelupanya diketahui Bonar","Ira yang pelupa sehingga dimanfaatkan oleh pembantunya","Bonar yang tidak mengetahuinya sifatnya istrinya yang pelupa","Bonar yang memahami istrinya karena teledor","Pembantu yang dimarahi Bonar karena ketahuan mencuri uang","","","","","","1","0","0","10","5");
INSERT INTO cbt_soal VALUES("1163","BIND_ALL","BINDO","","19","","Salah satu upaya menjaga saluran pencernaan agar tetap sehat, makanlah dengan pola makan sehat dan seimbang. Padahal keseimbangan makanan terbukti memelihara kesehatan secara fisik, mental, dan mampu memelihara prestasi kerja. Dianjurkan untuk mengonsumsi makanan yang tergolong makanan berenergi tinggi seperti susu, mentega, dan keju. Janganlah makan-makanan yang mengacu pada makanan budaya barat seperti pizza, fried chicken, dan lain-lain. .... <br /><br />Kalimat simpulan yang tepat untuk melengkapi paragraf tersebut adalah...","","","","Jadi, mulailah dengan diri anda","Jadi, olahraga teratur sangat bermanfaat bagi kebugaran tubuh","Jadi, kesehatan adalah tanggung jawab bersama","Jadi, awali hari anda dengan hal-hal yang positif","Jadi, mulailah hidup anda sehari-hari dengan makan-makanan yang higienis dan bergizi tinggi","","","","","","5","0","0","10","5");
INSERT INTO cbt_soal VALUES("1164","BIND_ALL","BINDO","","20","","Cermati paragraf berikut! <br /><br />Siswa kelas XII, SMA Negeri 3 Pandaan berjumlah 33 orang, setelah mengikuti ujian Bahasa Indonesia, 4 orang mendapat nilai 9, 10 orang mendapat nilai 8, 16 orang mendapat nilai 7, sisanya mendapat nilai 6.5. &hellip; <br /><br />Simpulan yang tepat untuk melengkapi paragraf tersebut adalah &hellip;.","","","","Jadi kelas XII SMA Negeri 3 Pandaan banyak yang bernilai tinggi dalam ujian Bahasa Indonesia.","Tidak heran kelas XII SMA Negeri 3 Pandaan selalu juara dalam ujian.","Dapat disimpulkan nilai Bahasa Indonesia kelas XII SMA Negeri 3 Pandaan bagus-bagus","Jadi, siswa kelas XII SMA Negeri 3 Pandaan cukup pandai dalam mata pelajaran Bahasa Indonesia","Sudah sepantasnya kelas XII SMA Negeri 3 Pandaan mendapat nilai bagus-bagus.","","","","","","4","0","0","10","5");
INSERT INTO cbt_soal VALUES("1160","BIND_ALL","BINDO","","16","","Bagi Bung Karno, yang ketika kecil bernama Kusno, ini tampaknya tak ada kisah manis bagi negara-negara miskin yang membangun dengan modal dari bantuan asing. Semua tetek bengek manajemen pembangunan yang diperbantukan dan arus teknologi modern yang dialihkan agar si miskin jadi kaya dan mengejar Barat hanyalah alat pengisap kekayaan si miskin yang membuatnya makin terbelakang. Cermati biografi berikut!. Itulah Bung Karno yang berhasil menggelorakan semangat revolusi dan mengajak berdiri di atas kaki sendiri bagi bangsanya, walaupun belum sempat berhasil membawa rakyatnya dalam kehidupan yang sejahtera. Konsep \"berdiri di atas kaki sendiri\" memang belum sampai ke tujuan tetapi setidaknya berhasil memberikan kebanggaan pada eksistensi bangsa. Daripada berdiri di atas utang luar negeri yang terbukti menghadirkan ketergantungan dan ketidakberdayaan (neokolonialisme). Masa kecil Bung Karno sudah diisi semangat kemandirian. Ia hanya beberapa tahun hidup bersama orang tua di Blitar. Semasa SD hingga tamat, ia tinggal di Surabaya, indekos di rumah Haji Oemar Said Tjokroaminoto, politisi kawakan pendiri Syarikat Islam. Kemudian melanjut di HBS (Hoogere Burger School). Saat belajar di HBS itu ia pun telah menggembleng jiwa nasionalismenya. Selepas lulus HBS tahun 1920, ia pindah ke Bandung dan melanjutkan ke THS (Technische Hooge-school atau Sekolah Tekhnik Tinggi yang sekarang menjadi ITB. Ia berhasil meraih gelar \"Ir\" pada 25 Mei 192. <br /><br />Mengapa Bung Karno menanamkan konsep &ldquo;berdiri di atas kaki sendiri&rdquo;?","","","","Karena utang luar negeri terbukti menghadirkan ketergantungan dan ketidakberdayaan (neokolonialisme)","Karena negara Indonesia adalah negara kaya apabila dikelola secara benar","Karena negara kita negara yang tidak berdaya","Karena hanya akan membuat yang kaya jauh lebih kaya","Karena dia ingin bangsanya mandiri","","","","","","1","0","0","10","5");
INSERT INTO cbt_soal VALUES("1161","BIND_ALL","BINDO","","17","","Cermati pantun berikut! <br /><br /><em>Tumbuh merata pohon tebu </em><br /><em>Pergi ke pasar membeli daging </em><br /><em>Banyak harta miskin ilmu </em><br /><em>.............................................</em> <br /><br />Larik yang tepat untuk melengkapi pantun tersebut adalah&hellip;","","","","Bagai rumah tidak berdinding","Bagai bunga kembang tak jadi","Bagai bola sedang menggelinding","","Bagai asap tanpa api","","","","","","1","0","0","10","5");
INSERT INTO cbt_soal VALUES("1162","BIND_ALL","BINDO","","18","","Cermati paragraf berikut! <br /><br />Salah satu upaya menjaga saluran pencernaan agar tetap sehat, makanlah dengan pola makan sehat dan seimbang. Padahal keseimbangan makanan terbukti memelihara kesehatan secara fisik, mental, dan mampu memelihara prestasi kerja. Dianjurkan untuk mengonsumsi makanan yang tergolong makanan berenergi tinggi seperti susu, mentega, dan keju. Janganlah makan-makanan yang mengacu pada makanan budaya barat seperti pizza, fried chicken, dan lain-lain. .... <br /><br />Kalimat tanya yang sesuai dengan paragraf tersebut adalah...","","","","Bagaimana mendapatkan bentuk tubuh yang sehat dan ideal?","Bagaimana cara menjaga kebugaran tubuh.","Di mana kita bisa dapatkan makanan yang higienis dan bergizi tinggi?","Berapa proporsi ideal makanan yang dapat dikategorikan sehat?","Berapa proporsi ideal makanan yang dapat dikategorikan sehat?","","","","","","1","0","0","10","5");
INSERT INTO cbt_soal VALUES("1153","BIND_ALL","BINDO","","9","","<strong>Cermatilah paragraf berikut!</strong><br /><br />(1) Berbagai perkembangan yang telah terjadi di bidang teknik informasi dalam beberapa tahun terakhir, hendaknya ditanggapi bukan dengan sikap cemas. (2) Perkembangan tersebut justru harus dilihat dari sisi positif. (3 )Sembari menyiasati berbagai kemungkinan untuk ikut memetik keuntungan dari perkembangan teknologi informasi yang berlangsung cepat dibandingkan perkembangan masyarakat. (5) Perkembangan ini pasti akan mengubah banyak hal dalam masyarakat, mulai dari gaya hidup, kecenderungan mental, hingga ke pandangan hidup. <br /><br />Ide pokok paragraf tersebut adalah &hellip;.","","","","Berbagai perkembangan yang terjadi","Perkembangan ditanggapi dengan cemas","Perkembangan teknologi informasi","Menyiasiati berbagai kemungkinan","Gaya dan pandangan hidup masyarakat","","","","","","3","0","0","10","5");
INSERT INTO cbt_soal VALUES("1159","BIND_ALL","BINDO","","15","","<strong>Cermati Biografi Berikut!</strong><br /><br />Bagi Bung Karno, yang ketika kecil bernama Kusno, ini tampaknya tak ada kisah manis bagi negara-negara miskin yang membangun dengan modal dari bantuan asing. Semua tetek bengek manajemen pembangunan yang diperbantukan dan arus teknologi modern yang dialihkan agar si miskin jadi kaya dan mengejar Barat hanyalah alat pengisap kekayaan si miskin yang membuatnya makin terbelakang. Cermati biografi berikut!. Itulah Bung Karno yang berhasil menggelorakan semangat revolusi dan mengajak berdiri di atas kaki sendiri bagi bangsanya, walaupun belum sempat berhasil membawa rakyatnya dalam kehidupan yang sejahtera. Konsep \"berdiri di atas kaki sendiri\" memang belum sampai ke tujuan tetapi setidaknya berhasil memberikan kebanggaan pada eksistensi bangsa. Daripada berdiri di atas utang luar negeri yang terbukti menghadirkan ketergantungan dan ketidakberdayaan (neokolonialisme). Masa kecil Bung Karno sudah diisi semangat kemandirian. Ia hanya beberapa tahun hidup bersama orang tua di Blitar. Semasa SD hingga tamat, ia tinggal di Surabaya, indekos di rumah Haji Oemar Said Tjokroaminoto, politisi kawakan pendiri Syarikat Islam. Kemudian melanjut di HBS (Hoogere Burger School). Saat belajar di HBS itu ia pun telah menggembleng jiwa nasionalismenya. Selepas lulus HBS tahun 1920, ia pindah ke Bandung dan melanjutkan ke THS (Technische Hooge-school atau Sekolah Tekhnik Tinggi yang sekarang menjadi ITB. Ia berhasil meraih gelar \"Ir\" pada 25 Mei 192. <br /><br />Hal yang dapat diteladani dari Bung Karno adalah...","","","","Ingin bangsa Indonesia bergantung dengan modal asing","Sejak usia sekolah berpisah dengan orang tuanya","Selalu menggelorakan semangat revolusi","Sejak kecil hidup dalam kemandirian","Digembleng jiwa nasionalisme selama di sekolah","","","","","","4","0","0","10","5");
