INSERT INTO cbt_soal VALUES("1157","BIND_ALL","BINDO","","13","","Topik : Kurangnya minat baca di kalangan siswa Latar belakang yang sesuai dengan topik tersebut adalah &hellip;.<br /><br />Kalimat rumusan masalah yang tepat untuk topik tersebut adalah...","","","","Bagaimana langkah-langkah meningkatkan minat baca siswa?","Apakah ada cara untuk meningkatkan minat baca siswa?","Siapa yang bertanggung jawab atas turunnya minat baca siswa?","Berapa waktu ideal seorang siswa dikategorikan minat bacanya baik?","Bagaimana respon guru terhadap turunnya minat baca siswa?","","","","","","1","0","0","10","5");
INSERT INTO cbt_soal VALUES("1155","BIND_ALL","BINDO","","11","","(1) Berbagai perkembangan yang telah terjadi di bidang teknik informasi dalam beberapa tahun terakhir, hendaknya ditanggapi bukan dengan sikap cemas. (2) Perkembangan tersebut justru harus dilihat dari sisi positif. (3 )Sembari menyiasati berbagai kemungkinan untuk ikut memetik keuntungan dari perkembangan teknologi informasi yang berlangsung cepat dibandingkan perkembangan masyarakat. (5) Perkembangan ini pasti akan mengubah banyak hal dalam masyarakat, mulai dari gaya hidup, kecenderungan mental, hingga ke pandangan hidup.<br /><br />Penggunaan istilah yang tidak tepat terdapat dalam kalimat nomor &hellip;","","","","1","2","3","4","5","","","","","","3","0","0","10","5");
