INSERT INTO cbt_soal VALUES("1320","BIO_IPA","BIO_IPA","","2","","Seorang siswa ingin mengetahui pengaruh cahaya terhadap kecepatan pertumbuhan kecambah,. Dia menanam kecambah kacang hijau di dalam gelas plastik kemudian ditumbuhkan dalam kotak yang sama sekali tidak mengandung cahaya (gelap), yang satu ditumbuhkan di dalam kotak yang cahayanya remang-remang, satunya lagi ditumbuhkan di tempat yang mendapat banyak cahaya. Setelah satu minggu tinggi kecambah diukur. Tentukan variabel manipulatif dari penelitian tersebut ....","","","","intensitas cahaya","jumlah dan ukuran kotak","tinggi kecambah","ukuran gelas plastik","jenis cahaya","","","","","","1","0","0","10","5");
