INSERT INTO cbt_soal VALUES("1329","BIO_IPA","BIO_IPA","","11","","Proses pembuatan manisan buah dilakukan dengan cara merendam irisan buah pada larutan gula yang pekat. Pada prinsipnya pembuatan manisan buah memanfaatkan peristiwa transpor zat melalui membran yaitu proses  ...","","","","osmosis, melalui perpindahan molekul air dari daerah berkonsentrasi rendah ke daerah berkonsentrasi tinggi melalui selaput semi permeabel"," osmosis, melalui perpindahan molekul gula dari buah menuju ke larutan gula pada saat peremdaman ","difusi, melalui proses perpindahan molekul air dari larutan hipertonis ke larutan hipotonis","difusi, melalui proses perpindahan molekul zat terlarut dari buah ke dalam larutan gula","transpor aktif, menggunakan energi berupa ATP untuk menggerakkan molekul gula agar tersebar merata","","","","","","1","0","0","10","5");
