INSERT INTO cbt_soal VALUES("1331","BIO_IPA","BIO_IPA","","13","","Dibawah ini adalah beberapa ciri jaringan tumbuhan: 1. Sel-sel berdinding tebal 2. Sel-sel rapat dan tidak memiliki ruang antar sel 3. Sel dapat bermodifikasi menjadi trikoma dan bulu akar 4. Sel-sel dapat bermodifikasi membentuk stomata 5. Sel memiliki banyak kloroplas  6. Sel-sel aktif melakukan pembelahan Karakterisitik yang dimiliki jaringan epidermis adalah â¦ .","","","","1 â 2 â 3","1 â 2 â 4","1 â 3 â 5","2 â 3 â 4","2 â 4 â 6","","","","","","4","0","0","10","5");
