INSERT INTO cbt_soal VALUES("1352","BIO_IPA","BIO_IPA","","34","","Perhatikan gamabr perangkat percobaan Spallanzani berikut ini Setelah dibiarkan terbuka selama 2 hari, air kaldu pada labu 4 berubah menjadi keruh dan mengandung mikroba. Hal ini membuktikan bahwa ....","","","","air kaldu yang dipanaskan belum mematikan mikroba","udara kotor dapat menyebabkan air kaldu keruh","air kaldu yang terbuka dapat berubah menjadi mikroorganisme","mikroba terbentuk dari air kaldu yang dibiarkan terbuka","mikroba dalam air kaldu berasal dari udara","","","","","","5","0","0","10","5");
INSERT INTO cbt_soal VALUES("1353","BIO_IPA","BIO_IPA","","35","","Pernyataan di bawah ini menyebabkan perubahan leher jerapah: <br />1) Jerapah bereher panjang berasal dari induk jerapah berleher pendek <br />2) Pada masa lampau terdapat jerapah berleher panjang maupun jerapah berleher pendek <br />3) Memanjangkan leher jerapah karena pengaruh lingkungan <br />4) jerapah berleher pendek mati, sedangkan berleher panjang tetap lestari/hidup <br /><br />Menurut teori evolusi Darwin yang ada hubungannya dengan evolusi jerapah adalah .....","","","","1 dan 2","1 dan 4","2 dan 3","2 dan 4","3 dan 4","","","","","","4","0","0","10","5");
INSERT INTO cbt_soal VALUES("1354","BIO_IPA","BIO_IPA","","36","","Salah satu petunjuk evolusi adalah adanya homologi dan analogi pada organ. Sayap kupu-kupu dengan sayap burung adalah dua organ yang analog. Tungkai depan kucing, tungkai depan katak, sayap kelelawar dan tangan manusia adalah organ yang homolog karena ....","","","","struktur dasar  sama  tetapi fungsinya berbeda","struktur dasar berbeda tetapi fungsi sama","struktur dasar dan fungsi sama","struktur dasar dan fungsi berbeda","struktur dasar dan fungsi berlawanan ","","","","","","1","0","0","10","5");
INSERT INTO cbt_soal VALUES("1355","BIO_IPA","BIO_IPA","","37","","Pernyataan berikut yang mendukung mekanisme evolusi yang terjadi akibat adanya seleksi alam adalah ....","","","","ular tidak berkaki dikarenakan kebiasaannya merayap di tanah","itik memiliki selaput sehingga memudahkannya untuk berenang","burung yang hidup di pinggir pantai mempunyai kaki dan leher panjang untuk menangkap ikan","punahnya kupu-kupu berwarna cerah dan meningkatnya kupu-kupu gelap terjadi karena perkembangan industri yang pesat","jerapah berleher panjang muncul karena kebiasaan menjulrkan leher untuk mencapai tunas daun yang tinggi","","","","","","4","0","0","10","5");
INSERT INTO cbt_soal VALUES("1356","BIO_IPA","BIO_IPA","","38","","Seorang pengusaha ingin membuka perkebunan jati dengan luas ratusan hektar. Oleh karena itu dibutuhkan bibit tanaman jati dalam jumlah yang banyak dan dalam waktu yang singkat. Prinsip bioteknologi yang dapat diterapkan untuk membantu pengusaha tersebut adalah ....","","","","teknik hibridoma","teknik transfer inti","teknik rekayasa genetika","teknik fusi sel","teknik kultur jaringan","","","","","","5","0","0","10","5");
