INSERT INTO cbt_soal VALUES("1237","EKO_IPS","EKO_IPS","","1","","Produsen teh botol menggunakan teknologi modern dalam proses produksi dan pengemasan. Semua tahap produksi dilakukan dengan mesin. Botol-botol yang akan digunakan terlebih dahulu melewati proses pencucian dengan suhu tinggi agar steril. Setelah tahap pencucian, air teh dimasukkan dalam keadaan panas, kemudian botol ditutup dengan rapat. Tahap penutupan botol dilakukan dengan teknologi yang membuat tutup kemasan menjadi kedap udara. Hal tersebut untuk menjamin teh dapat bertahan lama. Proses produksi teh botol tersebut menyangkut permasalahan ekonomi modern tentang ...","","","","       teknik produksi yang digunakan"," jenis barang yang diproduksi.","konsumen yang dituju","cara pendistribusian barang","cara mencapai keuntungan","","","","","","1","0","0","10","5");
