INSERT INTO cbt_soal VALUES("1245","EKO_IPS","EKO_IPS","","9","","Pergerakan harga barang kebutuhan pokok dan barang-barang lain terus menunjukkan kenaikan. Hal ini mengindikasikan adanya inflasi. Dampak negatif dari inflasi terhadap perdagangan internasional adalah ....","","",""," kesulitan bersaing bagi eksportir disebabkan oleh naiknya harga bahan Baku"," karyawan yang gajinya tidak mengalami kenaikan akan mendapatkan barang dan jasa dalam jumlah semakin sedikit"," pada kuantitas produksi yang sama, produsen akan mengeluarkan biaya produksi lebih tinggi","pihak yang memiliki utang (debitur) sulit membayar karena nilai utang semakin tinggi"," inflasi mendorong orang untuk berspekulasi dengan rnenggunakan sumber ekonomi yang tidak efisien sehingga berakibat pada turunnya produksi","","","","","","1","0","0","10","5");
