INSERT INTO cbt_soal VALUES("1250","EKO_IPS","EKO_IPS","","14","","Pak Toga bekerja di sebuah perusahaan per­kebunan kelapa sawit di Kalimantan. Perusahaan tersebut membuka cabang baru di Jakarta. Untuk mengembangkan cabang baru tersebut, Pak Toga diberi tugas memimpin cabang baru di Jakarta. Pak Toga kemudian menjual rumahnya di Kalimantan untukmembelirumah baru di Jakarta. Berdasarkan uraian tersebut, Pak Toga menjalan­kan Fungsi uang sebagai alat ....","","","","  transaksi yang sah"," pemindah kekayaan","penimbun kekayaan","pembayaran pada masa depan","pembayaran pada masa depan","","","","","","2","0","0","10","5");
