INSERT INTO cbt_soal VALUES("1254","EKO_IPS","EKO_IPS","","18","","Di Indonesia dijumpai banyak produk mainan anak yang berasal dari Cina. Hal tersebut mengakibat­kan jumlah permintaan produk mainan anak produksi dalam negeri turun. Untuk mengatasi hal tersebut, pemerintah Indonesia memberlakukan bea masuk atas impor barang tertentu agar produk mainan anak dari Cina tidak membanjir. Tindakan pemerintah ini disebut kebijakan ....","","","","kuota"," larangan impor","dumping"," tarif"," larangan ekspor","","","","","","1","0","0","10","5");
INSERT INTO cbt_soal VALUES("1255","EKO_IPS","EKO_IPS","","19","","1.        Mr. Rudolf adalah Warga Negara asing yang datang ke bank devisa untuk menukarkan uang sebesar US$50.000. Kurs yang berlaku pada hari itu, kurs beli Rp8.500,00, kurs jual Rp9.150,00, dan kurs tengah Rp8.825,00. Jumlah rupiah yang diperoleh Mr. Rudolf adalah ....","","",""," Rp410.000.000.00"," Rp415.000.000.00","Rp420 000.000,00"," Rp425.000.000.00","Rp425.500.000.00","","","","","","4","0","0","10","5");
